const path = require('path');

const LIB = require('../lib/jibo-cai-utils');
const PromiseUtils = LIB.PromiseUtils;
const TimeUtils = LIB.TimeUtils;
const PromiseQueueState = LIB.PromiseQueueState;
const PromiseQueue = LIB.PromiseQueue;

const DELTA_MS = 60;

describe('PromiseUtils', () => {

	it('wait and firstToSucceed #1', (done) => {
		let start = Date.now();
		PromiseUtils.firstToSucceed([
			TimeUtils.wait(100),
			TimeUtils.wait(150),
			TimeUtils.wait(200),
		]).then( () => {
			let time = Date.now() - start;
			expect(Math.abs(100 - time)).to.be.lessThan(DELTA_MS);
			done();
		}).catch(done);
	});

	it('wait and firstToSucceed #2', (done) => {
		let start = Date.now();
		PromiseUtils.firstToSucceed([
			TimeUtils.wait(100).then( () => 5),
			Promise.reject(''),
			Promise.reject(''),
		]).then( (data) => {
			let time = Date.now() - start;
			expect(data).to.equal(5);
			expect(Math.abs(100 - time)).to.be.lessThan(DELTA_MS);
			done();
		}).catch(done);
	});

	it('firstToSucceed #3', (done) => {
		PromiseUtils.firstToSucceed([
			Promise.reject(1),
			TimeUtils.wait(10).then( () => Promise.reject(2)),
			Promise.reject(3),
		]).then( () => {
			done('error');
		}).catch( (errors) => {
			expect(errors).to.deep.equal([1,2,3]);
			done();
		});
	});

	it('PromiseQueue', (done) => {
		let q = new PromiseQueue();
		let arr = [];
		expect(q.getState()).to.equal(PromiseQueueState.NOT_PLAYING);
		q.add( () => TimeUtils.wait(5).then( () => arr.push(1)) );
		expect(q.getState()).to.equal(PromiseQueueState.PLAYING);
		q.add( () => TimeUtils.wait(10).then( () => arr.push(2)) );
		q.add( () => TimeUtils.wait(15).then( () => arr.push(3)) );

		q.waitUntilEmpty().then( () => {
			expect(q.getState()).to.equal(PromiseQueueState.NOT_PLAYING);
			expect(arr).to.deep.equal([1,2,3]);
			done();
		}).catch(done);
	});

	it('PromiseQueue un-added wait', (done) => {
		let q = new PromiseQueue();
		expect(q.getState()).to.equal(PromiseQueueState.NOT_PLAYING);
		q.waitUntilEmpty().then( () => {
			expect(q.getState()).to.equal(PromiseQueueState.NOT_PLAYING);
				done();
			});
	});

	it('PromiseQueue clearing', (done) => {
		let q = new PromiseQueue();
		const getTimeoutPr = () => {
			return new Promise( res => setTimeout(res, 100) );
		};

		let startTime = Date.now();
		q.add(getTimeoutPr);
		q.add(getTimeoutPr);
		q.add(getTimeoutPr);
		q.add( () => {
			return Promise.resolve().then( () => {
				expect(q.getState()).to.equal(PromiseQueueState.PLAYING);
				q.clear();
			});
		});
		q.add(getTimeoutPr);
		q.add(getTimeoutPr);
		q.add(getTimeoutPr);

		
		q.waitUntilEmpty().then( () => {
			let time = Date.now() - startTime;
			expect(q.getState()).to.equal(PromiseQueueState.NOT_PLAYING);
			expect(Math.abs(time - 300)).to.be.lessThan(DELTA_MS);
			done();
		}).catch(done);
	});

	it('PromiseQueue error handling', (done) => {
		let q = new PromiseQueue();
		let errored = false;
		let arr = [];

		expect(q.getState()).to.equal(PromiseQueueState.NOT_PLAYING);
		q.add( () => TimeUtils.wait(5).then( () => arr.push(1)) );
		expect(q.getState()).to.equal(PromiseQueueState.PLAYING);
		q.add( () => TimeUtils.wait(5).then( () => arr.push(2)) );
		q.add( () => TimeUtils.wait(5).then( () => arr.push(3)) );
		q.add( () => TimeUtils.wait(5).then( () => { throw Error(`Rejected`); }) );

		q.waitUntilEmpty()
			.catch( err => {
				expect(q.getState()).to.equal(PromiseQueueState.NOT_PLAYING);
				errored = true;
				expect(err).to.eql(new Error(`Rejected`));
				expect(arr).to.deep.equal([1,2,3]);
				q.add( () => TimeUtils.wait(5).then( () => arr.push(4)) );
				expect(q.getState()).to.equal(PromiseQueueState.PLAYING);
				q.add( () => TimeUtils.wait(5).then( () => arr.push(5)) );
				q.waitUntilEmpty().then( () => {
					expect(q.getState()).to.equal(PromiseQueueState.NOT_PLAYING);
					expect(arr).to.deep.equal([1,2,3,4,5]);
				});
			})
			.then( () => {
				expect(errored).to.be.true;
				done();
			})
			.catch(done);

	});

	it('Promisify', (done) => {
		let testFunc = (data, error, cb) => {
			process.nextTick(() => {
				if (error) {
					cb(error);
				}
				else {
					cb(undefined, data);
				}
			});
		};

		PromiseUtils.promisify( (handler) => testFunc(1, undefined, handler) )
			.then( (data) => {
				expect(data).to.equal(1);

				PromiseUtils.promisify( (handler) => testFunc(1, 'e', handler) )
					.then( () => done('error') ).catch( (e) => {
						expect(e).to.equal('e');
						done();
					});

			}).catch(done);
	});

	it('Promisify with non-first-arg-error', (done) => {
		let irregularAsyncFunc = (data, cb) => {
			process.nextTick(() => {
				cb(data);
			});
		};

		PromiseUtils.promisify( (handler) => irregularAsyncFunc(1, handler), false )
			.then( (data) => {
				expect(data).to.equal(1);
				done();
			}).catch(done);
	});
});
